#include <stdio.h>
#include <math.h>

#define N 6    // number of data points
#define DEGREE 3     // polynomial degree

// function to fit a polynomial to data points
void polynomial_fit(double x[], double y[], int n, int degree, double c[])
{
    double X[2*degree+1];
    for(int i=0; i<2*degree+1; i++)
    {
        X[i] = 0;
        for(int j=0; j<n; j++)
            X[i] += pow(x[j], i);
    }

    double Y[degree + 1];
    for(int i=0; i<degree+1; i++)
    {
        Y[i] = 0;
        for(int j=0; j<n; j++)
            Y[i] += pow(x[j], i) * y[j];
    }

    double B[degree+1][degree+2];
    for(int i=0; i<=degree; i++)
        for(int j=0; j<=degree; j++)
            B[i][j] = X[i+j];

    for(int i=0; i<=degree; i++)
        B[i][degree+1] = Y[i];

    degree += 1;

    for(int i=0; i<degree; i++) 
    {
        for(int k=i+1; k<degree; k++)
        {
            if(B[i][i] < B[k][i])
            {
                for(int j=0; j<=degree; j++)
                {
                    double temp = B[i][j];
                    B[i][j] = B[k][j];
                    B[k][j] = temp;
                }
            }
        }
    }

    for(int i=0; i<degree-1; i++)
    {
        for(int k=i+1; k<degree; k++)
        {
            double t = B[k][i]/B[i][i];
            for(int j=0; j<=degree; j++)
                B[k][j] -= t*B[i][j];
        }
    }

    for(int i=degree-1; i>=0; i--)
    {
        c[i] = B[i][degree];
        for(int j=i+1; j<degree; j++)
            c[i] -= B[i][j]*c[j];
        c[i] /= B[i][i];
    }

    printf("Coefficients of the polynomial are: ");
    for(int i=0;i<DEGREE;i++)
        printf("%.3f, ",c[i]);
    printf("\n");
}

int main()
{
    double x[N] = {0, 1, 2, 3, 4, 5};
    double y[N] = {0, 1.2, 2.4, 3.6, 4.8, 6};
    double coeff[DEGREE];

    polynomial_fit(x, y, N, DEGREE, coeff);

    // linearize the DAC output using the polynomial function
    double input_voltage = 2.5;
    double output_voltage = coeff[0] + coeff[1]*input_voltage + coeff[2]*pow(input_voltage, 2) + coeff[3]*pow(input_voltage, 3);

    printf("Output voltage for %f input voltage is %.3f\n", input_voltage, output_voltage);

    return 0;
}
